const ctx = $json;
const rfp = ctx.rfp || {};
const sourceType = rfp.source_type || 'unknown';
const meta = rfp.source_metadata || {};
const received = rfp.received_at ? new Date(rfp.received_at).toLocaleString() : '';

let sourceLabel = sourceType;
let sourceDetail = '';
if (sourceType === 'email') {
  sourceLabel = 'Email';
  sourceDetail = meta.from || '(unknown sender)';
} else if (sourceType === 'sam_gov') {
  sourceLabel = 'SAM.gov';
  sourceDetail = meta.notice_id || rfp.external_id || '(no notice id)';
} else if (sourceType === 'manual_upload') {
  sourceLabel = 'Manual upload';
  sourceDetail = meta.filename || '(no filename)';
} else if (sourceType === 'url_ingest') {
  sourceLabel = 'URL';
  sourceDetail = meta.url || rfp.source_url || '';
}

const uiUrl = $env.KAIZEN_UI_URL || 'http://localhost:8501';
const reviewUrl = `${uiUrl}/?rfp=${rfp.id}`;

const payload = {
  text: `:inbox_tray: New RFP ingested: ${rfp.title || '(no title)'}`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `:inbox_tray: New RFP ingested: ${rfp.title || '(no title)'}`.slice(0, 150), emoji: true } },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: `*Source type*\n${sourceLabel}` },
      { type: 'mrkdwn', text: `*Source details*\n${sourceDetail}` },
      { type: 'mrkdwn', text: `*Agency*\n${rfp.agency || '—'}` },
      { type: 'mrkdwn', text: `*Ingested at*\n${received}` }
    ] },
    { type: 'context', elements: [{ type: 'mrkdwn', text: '_No screening has run yet. A screening card will follow shortly if `config.mode` is `chain` or `full_auto`._' }] },
    { type: 'actions', elements: [
      { type: 'button', text: { type: 'plain_text', text: 'Review in dashboard' }, url: reviewUrl, style: 'primary' }
    ] }
  ]
};
return [{ json: payload }];
